// TypeScript implementation for Literal Value Types
interface LiteralValueTypesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processLiteralValueTypes(item: LiteralValueTypesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processLiteralValueTypes({ id: 1, title: 'Literal Value Types', status: 'active' }));

